import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';
import type { AnalyticsQuery, TimeGranularity } from '../../src/models/analytics.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeOrder(overrides: Partial<Order> & { id: string }): Order {
  return {
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 100,
    status: 'pending',
    createdAt: new Date('2025-01-15'),
    updatedAt: new Date('2025-01-15'),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: `${overrides.id}@example.com`,
    role: 'member',
    createdAt: new Date('2025-01-15'),
    updatedAt: new Date('2025-01-15'),
    ...overrides,
  };
}

function makeQuery(overrides?: Partial<AnalyticsQuery>): AnalyticsQuery {
  return {
    timeRange: {
      start: new Date('2025-01-01'),
      end: new Date('2025-01-31'),
    },
    granularity: 'day' as TimeGranularity,
    ...overrides,
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('AnalyticsService', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // -----------------------------------------------------------------------
  // getOrderAnalytics
  // -----------------------------------------------------------------------

  describe('getOrderAnalytics', () => {
    it('should return zeros for empty dataset', async () => {
      const result = await service.getOrderAnalytics(makeQuery());

      expect(result.totalOrders).toBe(0);
      expect(result.totalRevenue).toBe(0);
      expect(result.averageOrderValue).toBe(0);
      expect(result.statusBreakdown).toEqual({
        pending: 0,
        confirmed: 0,
        shipped: 0,
        delivered: 0,
        cancelled: 0,
      });
    });

    it('should aggregate a single order', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 50, status: 'pending' }));
      const result = await service.getOrderAnalytics(makeQuery());

      expect(result.totalOrders).toBe(1);
      expect(result.totalRevenue).toBe(50);
      expect(result.averageOrderValue).toBe(50);
      expect(result.statusBreakdown.pending).toBe(1);
    });

    it('should aggregate multiple orders', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, status: 'pending' }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, status: 'confirmed' }));
      orderRepo.save(makeOrder({ id: 'o3', total: 300, status: 'shipped' }));

      const result = await service.getOrderAnalytics(makeQuery());

      expect(result.totalOrders).toBe(3);
      expect(result.totalRevenue).toBe(600);
      expect(result.averageOrderValue).toBe(200);
      expect(result.statusBreakdown.pending).toBe(1);
      expect(result.statusBreakdown.confirmed).toBe(1);
      expect(result.statusBreakdown.shipped).toBe(1);
    });

    it('should filter orders by time range', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2025-01-15') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, createdAt: new Date('2025-02-15') }));

      const result = await service.getOrderAnalytics(makeQuery());

      expect(result.totalOrders).toBe(1);
      expect(result.totalRevenue).toBe(100);
    });

    it('should include revenue and order count time series', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 50, createdAt: new Date('2025-01-10') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 75, createdAt: new Date('2025-01-10') }));
      orderRepo.save(makeOrder({ id: 'o3', total: 100, createdAt: new Date('2025-01-20') }));

      const result = await service.getOrderAnalytics(makeQuery());

      expect(result.revenueSeries.label).toBe('revenue');
      expect(result.orderCountSeries.label).toBe('orders');

      // Check that the time series points contain the correct totals
      const jan10Revenue = result.revenueSeries.points.find(
        (p) => p.timestamp.getTime() === new Date('2025-01-10').getTime(),
      );
      expect(jan10Revenue?.value).toBe(125);

      const jan20Revenue = result.revenueSeries.points.find(
        (p) => p.timestamp.getTime() === new Date('2025-01-20').getTime(),
      );
      expect(jan20Revenue?.value).toBe(100);
    });

    it('should count all status types correctly', async () => {
      orderRepo.save(makeOrder({ id: 'o1', status: 'pending' }));
      orderRepo.save(makeOrder({ id: 'o2', status: 'confirmed' }));
      orderRepo.save(makeOrder({ id: 'o3', status: 'shipped' }));
      orderRepo.save(makeOrder({ id: 'o4', status: 'delivered' }));
      orderRepo.save(makeOrder({ id: 'o5', status: 'cancelled' }));

      const result = await service.getOrderAnalytics(makeQuery());

      expect(result.statusBreakdown).toEqual({
        pending: 1,
        confirmed: 1,
        shipped: 1,
        delivered: 1,
        cancelled: 1,
      });
    });
  });

  // -----------------------------------------------------------------------
  // getUserAnalytics
  // -----------------------------------------------------------------------

  describe('getUserAnalytics', () => {
    it('should return zeros for empty dataset', async () => {
      const result = await service.getUserAnalytics(makeQuery());

      expect(result.totalUsers).toBe(0);
      expect(result.newUsers).toBe(0);
      expect(result.usersByRole).toEqual({});
    });

    it('should count new users in range', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2025-01-10') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2025-01-20') }));
      userRepo.save(makeUser({ id: 'u3', createdAt: new Date('2025-02-15') })); // out of range

      const result = await service.getUserAnalytics(makeQuery());

      expect(result.newUsers).toBe(2);
      expect(result.totalUsers).toBe(3); // totalUsers counts all users
    });

    it('should group users by role', async () => {
      userRepo.save(makeUser({ id: 'u1', role: 'admin', createdAt: new Date('2025-01-10') }));
      userRepo.save(makeUser({ id: 'u2', role: 'member', createdAt: new Date('2025-01-10') }));
      userRepo.save(makeUser({ id: 'u3', role: 'member', createdAt: new Date('2025-01-10') }));
      userRepo.save(makeUser({ id: 'u4', role: 'viewer', createdAt: new Date('2025-01-10') }));

      const result = await service.getUserAnalytics(makeQuery());

      expect(result.usersByRole).toEqual({ admin: 1, member: 2, viewer: 1 });
    });

    it('should include new user time series', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2025-01-10') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2025-01-10') }));

      const result = await service.getUserAnalytics(makeQuery());

      expect(result.newUserSeries.label).toBe('newUsers');
      const jan10 = result.newUserSeries.points.find(
        (p) => p.timestamp.getTime() === new Date('2025-01-10').getTime(),
      );
      expect(jan10?.value).toBe(2);
    });
  });

  // -----------------------------------------------------------------------
  // getMetric
  // -----------------------------------------------------------------------

  describe('getMetric', () => {
    it('should return revenue metric', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100 }));

      const metric = await service.getMetric('revenue', makeQuery());

      expect(metric.type).toBe('revenue');
      expect(metric.currentValue).toBe(100);
    });

    it('should return orders metric', async () => {
      orderRepo.save(makeOrder({ id: 'o1' }));
      orderRepo.save(makeOrder({ id: 'o2' }));

      const metric = await service.getMetric('orders', makeQuery());

      expect(metric.type).toBe('orders');
      expect(metric.currentValue).toBe(2);
    });

    it('should return users metric', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2025-01-10') }));

      const metric = await service.getMetric('users', makeQuery());

      expect(metric.type).toBe('users');
      expect(metric.currentValue).toBe(1);
    });

    it('should return average-order-value metric', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200 }));

      const metric = await service.getMetric('average-order-value', makeQuery());

      expect(metric.type).toBe('average-order-value');
      expect(metric.currentValue).toBe(150);
    });

    it('should throw for unknown metric type', async () => {
      await expect(
        service.getMetric('unknown' as any, makeQuery()),
      ).rejects.toThrow('Unknown metric type');
    });

    it('should compute period-over-period change', async () => {
      // Previous period: Dec 2024 — 1 order at $100
      orderRepo.save(makeOrder({ id: 'o-prev', total: 100, createdAt: new Date('2024-12-15') }));
      // Current period: Jan 2025 — 1 order at $200
      orderRepo.save(makeOrder({ id: 'o-curr', total: 200, createdAt: new Date('2025-01-15') }));

      const metric = await service.getMetric('revenue', makeQuery());

      expect(metric.currentValue).toBe(200);
      expect(metric.previousValue).toBe(100);
      expect(metric.change).toBe(100); // 100% increase
    });

    it('should return 0 change when previous period is empty', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100 }));

      const metric = await service.getMetric('revenue', makeQuery());

      expect(metric.currentValue).toBe(100);
      expect(metric.previousValue).toBe(0);
      expect(metric.change).toBe(0);
    });
  });

  // -----------------------------------------------------------------------
  // getDashboard
  // -----------------------------------------------------------------------

  describe('getDashboard', () => {
    it('should return complete dashboard for empty dataset', async () => {
      const dashboard = await service.getDashboard(makeQuery());

      expect(dashboard.generatedAt).toBeInstanceOf(Date);
      expect(dashboard.timeRange).toEqual(makeQuery().timeRange);
      expect(dashboard.metrics).toHaveLength(4);
      expect(dashboard.orders.totalOrders).toBe(0);
      expect(dashboard.users.totalUsers).toBe(0);
    });

    it('should return complete dashboard with data', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, status: 'pending' }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, status: 'confirmed' }));
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2025-01-10') }));

      const dashboard = await service.getDashboard(makeQuery());

      expect(dashboard.orders.totalOrders).toBe(2);
      expect(dashboard.orders.totalRevenue).toBe(300);
      expect(dashboard.users.newUsers).toBe(1);
      expect(dashboard.metrics).toHaveLength(4);

      const revenueMetric = dashboard.metrics.find((m) => m.type === 'revenue');
      expect(revenueMetric?.currentValue).toBe(300);

      const ordersMetric = dashboard.metrics.find((m) => m.type === 'orders');
      expect(ordersMetric?.currentValue).toBe(2);
    });

    it('should include all four metric types', async () => {
      const dashboard = await service.getDashboard(makeQuery());

      const types = dashboard.metrics.map((m) => m.type);
      expect(types).toContain('revenue');
      expect(types).toContain('orders');
      expect(types).toContain('users');
      expect(types).toContain('average-order-value');
    });
  });

  // -----------------------------------------------------------------------
  // Edge cases
  // -----------------------------------------------------------------------

  describe('edge cases', () => {
    it('should handle orders at exact boundary of time range', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2025-01-01') })); // start
      orderRepo.save(makeOrder({ id: 'o2', total: 200, createdAt: new Date('2025-01-31') })); // end

      const result = await service.getOrderAnalytics(makeQuery());

      expect(result.totalOrders).toBe(2);
      expect(result.totalRevenue).toBe(300);
    });

    it('should handle large datasets', async () => {
      for (let i = 0; i < 100; i++) {
        const day = String((i % 28) + 1).padStart(2, '0');
        orderRepo.save(
          makeOrder({
            id: `o${i}`,
            total: 10,
            createdAt: new Date(`2025-01-${day}`),
          }),
        );
      }

      const result = await service.getOrderAnalytics(makeQuery());

      expect(result.totalOrders).toBe(100);
      expect(result.totalRevenue).toBe(1000);
      expect(result.averageOrderValue).toBe(10);
    });

    it('should handle different granularities', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2025-01-15') }));

      const weeklyQuery = makeQuery({ granularity: 'week' });
      const result = await service.getOrderAnalytics(weeklyQuery);

      expect(result.totalOrders).toBe(1);
      expect(result.revenueSeries.points.length).toBeGreaterThan(0);
    });

    it('should handle monthly granularity', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2025-01-15') }));

      const monthlyQuery = makeQuery({ granularity: 'month' });
      const result = await service.getOrderAnalytics(monthlyQuery);

      expect(result.totalOrders).toBe(1);
      expect(result.revenueSeries.points.length).toBeGreaterThanOrEqual(1);
    });

    it('should handle hourly granularity', async () => {
      const query = makeQuery({
        timeRange: {
          start: new Date('2025-01-15T00:00:00'),
          end: new Date('2025-01-15T23:59:59'),
        },
        granularity: 'hour',
      });
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2025-01-15T10:30:00') }));

      const result = await service.getOrderAnalytics(query);

      expect(result.totalOrders).toBe(1);
      expect(result.revenueSeries.points.length).toBe(24);
    });

    it('should handle zero-total orders', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 0 }));

      const result = await service.getOrderAnalytics(makeQuery());

      expect(result.totalOrders).toBe(1);
      expect(result.totalRevenue).toBe(0);
      expect(result.averageOrderValue).toBe(0);
    });
  });
});

